from django.contrib.auth.models import User
from django.contrib.sessions.models import Session
from django.views.decorators.csrf import csrf_exempt
from django.http import HttpResponse
from saml2.assertion import SAMLAssertion
from xml.etree import ElementTree as ET

@csrf_exempt
def saml_post_view(request):
    # Parse SAML XML from POST request
    xml = request.body.decode('utf-8')
    root = ET.fromstring(xml)

    # Validate XML structure
    if not root.tag == 'samlResponse':
        return HttpResponse('Invalid SAML XML structure', status=400)

    # Parse SAML assertion
    assertion = SAMLAssertion(xml)

    # Extract user information
    name_id = assertion.get_name_id()
    attributes = assertion.get_attributes()

    # Create Django user session
    user, _ = User.objects.get_or_create(username=name_id)
    session = Session.objects.create(session_key=name_id)
    session.save()

    # Set session variables
    for attribute in attributes:
        session[attribute] = attributes[attribute]

    # Redirect to portal homepage
    return HttpResponse(redirect('portal'))